import React, { useEffect } from "react";
import { Loader2, ShieldCheck } from "lucide-react";

export default function PaymentProcessingScreen({ message, onComplete }) {
  useEffect(() => {
    const timer = setTimeout(() => {
      if (typeof onComplete === "function") {
        onComplete();
      }
    }, 3000);

    return () => clearTimeout(timer);
  }, [onComplete]);

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-white px-6 animate-in fade-in duration-500">
      {/* Spinner */}
      <div className="relative mb-10">
        <div className="w-24 h-24 border-4 border-emerald-50 border-t-[#00875A] rounded-full animate-spin" />
        <div className="absolute inset-0 flex items-center justify-center">
          <Loader2 className="text-[#00875A] animate-pulse" size={32} />
        </div>
      </div>

      {/* Text */}
      <h2 className="text-2xl font-black text-gray-900 text-center mb-3 leading-tight">
        {message || "Securing your transaction..."}
      </h2>

      <p className="text-gray-400 font-bold text-center text-sm max-w-xs">
        Please do not close the app or refresh this page.
      </p>

      {/* Footer trust badge */}
      <div className="absolute bottom-10 flex items-center gap-2 text-gray-300">
        <ShieldCheck size={16} />
        <span className="text-[10px] font-black uppercase tracking-widest">
          PCI-DSS Compliant
        </span>
      </div>
    </div>
  );
}
